// Component shared functionality
uint16 NavigationComponent::GetOwningEntityId() const
{
	return this - &ArgusComponentRegistry::s_NavigationComponents[0];
}

void NavigationComponent::Reset()
{
	m_navigationPoints.Reset();
	m_queuedWaypoints.Reset();
	m_lastPointIndex = 0;
	m_groupLastPointIndex = 0;
	m_currentNavAgentToUse = FNavAgentSelector(0u);
	m_navAgentToUseWhenSolo = FNavAgentSelector(1u);
}

void NavigationComponent::Serialize(FArchive& archive)
{
	archive << m_navigationPoints;
	m_queuedWaypoints.Serialize(archive);
	archive << m_lastPointIndex;
	archive << m_groupLastPointIndex;
	m_navAgentToUseWhenSolo.Serialize(archive);
}

void NavigationComponent::DrawComponentDebug() const
{
#if !UE_BUILD_SHIPPING
	if (!ImGui::CollapsingHeader("NavigationComponent"))
	{
		return;
	}

	if (ImGui::BeginTable("ComponentValues", 2, ImGuiTableFlags_NoSavedSettings | ImGuiTableFlags_BordersInner))
	{
		ImGui::TableNextColumn();
		ImGui::Text("m_navigationPoints");
		ImGui::TableNextColumn();
		ImGui::Text("Array max is currently = %d", m_navigationPoints.Max());
		if (m_navigationPoints.Num() == 0)
		{
			ImGui::Text("Array is empty");
		}
		else
		{
			ImGui::Text("Size of array = %d", m_navigationPoints.Num());
			ImGui::Indent();
			for (int32 i = 0; i < m_navigationPoints.Num(); ++i)
			{
				if (i != 0) ImGui::Separator();
				ImGui::Text("(%.2f, %.2f, %.2f)", m_navigationPoints[i].X, m_navigationPoints[i].Y, m_navigationPoints[i].Z);
			}
			ImGui::Unindent();
		}
		ImGui::TableNextColumn();
		ImGui::Text("m_queuedWaypoints");
		ImGui::TableNextColumn();
		ImGui::TableNextColumn();
		ImGui::Text("m_lastPointIndex");
		ImGui::TableNextColumn();
		ImGui::Text("%d", m_lastPointIndex);
		ImGui::TableNextColumn();
		ImGui::Text("m_groupLastPointIndex");
		ImGui::TableNextColumn();
		ImGui::Text("%d", m_groupLastPointIndex);
		ImGui::TableNextColumn();
		ImGui::Text("m_currentNavAgentToUse");
		ImGui::TableNextColumn();
		if (!m_currentNavAgentToUse.ContainsAnyAgent())
		{
			ImGui::Text("None");
		}
		else
		{
			for (int32 i = 0; i < 16; ++i)
			{
				if (m_currentNavAgentToUse.Contains(i))
				{
					ImGui::Text("Agent Index %d", i);
					break;
				}
			}
		}
		ImGui::TableNextColumn();
		ImGui::Text("m_navAgentToUseWhenSolo");
		ImGui::TableNextColumn();
		if (!m_navAgentToUseWhenSolo.ContainsAnyAgent())
		{
			ImGui::Text("None");
		}
		else
		{
			for (int32 i = 0; i < 16; ++i)
			{
				if (m_navAgentToUseWhenSolo.Contains(i))
				{
					ImGui::Text("Agent Index %d", i);
					break;
				}
			}
		}
		ImGui::EndTable();
	}
#endif //!UE_BUILD_SHIPPING
}

